proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_entails_and_weakens_to_single(spec1: TempPred<int>, spec2: TempPred<int>, p: TempPred<int>)
    requires
        spec1.entails(p),
    ensures
        spec1.and(spec2).entails(p),
{
    assert forall |ex| #[trigger] spec1.and(spec2).satisfied_by(ex) implies p.satisfied_by(ex) by {
        implies_apply::<int>(ex, spec1, p);
    };
}

