proof fn phi_4_entails_and_self_redundant(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(p),
        spec.entails(q),
    ensures
        spec.and(spec).entails(p.and(q)),
{
    entails_and_different_temp::<int>(spec, spec, p, q);
}

proof fn phi_5_valid_implies_entails_anything(p: TempPred<int>, spec: TempPred<int>)
    requires
        valid(p),
    ensures
        spec.entails(p),
{
    assert forall |ex| #[trigger] spec.satisfied_by(ex) implies p.satisfied_by(ex) by {
        implies_apply::<int>(ex, spec, p);
    };
}
